state_json_schema.schema:
{
  "feature_name": "string",
  "branch_name": "string | null",
  "git_automation_enabled": boolean,
  "hands_off_mode": boolean,
  "smoke_test_automation": {
    "enabled": boolean,
    "environments": {
      "web": { "base_url": "string", "auth": "object | null", "viewport": "object | null", "mcp_available": boolean, "mcp_name": "string | null", "verified": boolean } | null,
      "native": { "app_id": "string", "appium_endpoint": "string | null", "mcp_available": boolean, "mcp_name": "string | null", "verified": boolean } | null,
      "desktop": { "executable_path": "string", "window_title": "string", "launch_args": "string | null", "mcp_available": boolean, "mcp_name": "string | null", "verified": boolean } | null
    },
    "missing_prerequisites": ["string"]
  },
  "skipped_smoke_tests": [
    { "step": number, "name": "string", "classification": "string", "description": "string" }
  ],
  "current_phase": number,
  "plan_status": "string",
  "total_steps": number,
  "current_step": number,
  "pivot_in_progress": boolean,
  "phase_5_substep": "string | null"
}

sub_branch.action:
Write the configuration to agent-workspace/testing-environments.json with all fields (mcp_available/mcp_name/verified initially false/null/false — populated by verification below). Include hands_off_mode from Part A:
                  {
                    "hands_off_mode": true|false,
                    "smoke_test_automation": {
                      "enabled": true,
                      "environments": {
                        "web": { "base_url": "[user-provided or null]", "auth": null, "mcp_available": false, "mcp_name": null, "verified": false },
                         "native": { "app_id": "[user-provided or null]", "appium_endpoint": "[user-provided or http://localhost:4723]", "mcp_available": false, "mcp_name": null, "verified": false },
                        "desktop": { "executable_path": "[user-provided or null]", "window_title": "[user-provided or null]", "mcp_available": false, "mcp_name": null, "verified": false }
                      }
                    }
                  }
